// Allows cancelling in-flight operations when user navigates away

let joinAbortController: AbortController | null = null;
let createAbortController: AbortController | null = null;

export function cancelJoinOperation(): void {
    if (joinAbortController) {
        joinAbortController.abort();
        joinAbortController = null;
    }
}

export function cancelCreateOperation(): void {
    if (createAbortController) {
        createAbortController.abort();
        createAbortController = null;
    }
}

export function cancelAllOperations(): void {
    cancelJoinOperation();
    cancelCreateOperation();
}

export function openMultiplayer(): void {
    // Pre-fill nickname from storage
    const storedNickname = safeGetItem('eigennamen-nickname', '') ?? '';
    const joinNicknameEl = document.getElementById('join-nickname') as HTMLInputElement | null;
    if (joinNicknameEl) joinNicknameEl.value = storedNickname;
    const createNicknameEl = document.getElementById('create-nickname') as HTMLInputElement | null;
    if (createNicknameEl) createNicknameEl.value = storedNickname;

    // Reset forms
    const joinRoomEl = document.getElementById('join-room-id') as HTMLInputElement | null;
    if (joinRoomEl) joinRoomEl.value = '';
    const createRoomEl = document.getElementById('create-room-id') as HTMLInputElement | null;
    if (createRoomEl) createRoomEl.value = '';
    setMpStatus('', '');
    clearFormErrors();

    // Reset to join mode
    setMpMode('join');

    openModal('multiplayer-modal');
}

export function closeMultiplayer(): void {
    cancelAllOperations();
    clearFormErrors();
    closeModal('multiplayer-modal');
}

export function setMpMode(mode: string): void {
    state.currentMpMode = mode;

    // Update mode buttons
    document.querySelectorAll('.mode-btn').forEach((btn) => {
        const el = btn as HTMLElement;
        el.classList.toggle('active', el.dataset.mode === mode);
    });

    // Show correct form
    const joinForm = document.getElementById('join-form');
    const createForm = document.getElementById('create-form');
    if (joinForm) joinForm.classList.toggle('active', mode === 'join');
    if (createForm) createForm.classList.toggle('active', mode === 'create');

    // Update action button text
    const actionBtn = document.getElementById('btn-mp-action');
    if (actionBtn) actionBtn.textContent = mode === 'join' ? t('multiplayer.joinGame') : t('multiplayer.createGame');
}

export function setMpStatus(message: string, type: string): void {
    const statusEl = document.getElementById('mp-status');
    if (!statusEl) return;
    statusEl.textContent = message;
    statusEl.className = 'connection-status';
    if (type) {
        statusEl.classList.add(type);
    }
}

export function setFieldError(message: string, fieldId: string): void {
    const errorEl = document.getElementById(fieldId);
    if (!errorEl) return;
    const formGroup = errorEl.closest('.form-group');
    errorEl.textContent = message;
    if (formGroup) {
        if (message) {
            formGroup.classList.add('error');
        } else {
            formGroup.classList.remove('error');
        }
    }
}

export function clearFormErrors(): void {
    ['join-error', 'join-nickname-error', 'create-error', 'create-nickname-error'].forEach((id) => {
        setFieldError('', id);
    });
}

export async function handleMpAction(): Promise<void> {
    const actionBtn = document.getElementById('btn-mp-action') as HTMLButtonElement;
    if (!actionBtn) return;

    const originalText = actionBtn.textContent;
    actionBtn.disabled = true;
    actionBtn.textContent = state.currentMpMode === 'join' ? t('multiplayer.joining') : t('multiplayer.creating');
    actionBtn.classList.add('loading');

    try {
        if (state.currentMpMode === 'join') {
            await handleJoinGame();
        } else {
            await handleCreateGame();
        }
    } catch (error: unknown) {
        const message = error instanceof Error ? error.message : 'Connection failed';
        logger.error('Multiplayer action failed:', error);
        setMpStatus(message, 'error');
    } finally {
        actionBtn.disabled = false;
        actionBtn.textContent = originalText;
        actionBtn.classList.remove('loading');
    }
}

async function handleJoinGame(): Promise<void> {
    clearFormErrors();

    const joinNicknameEl = document.getElementById('join-nickname') as HTMLInputElement | null;
    const joinRoomIdEl = document.getElementById('join-room-id') as HTMLInputElement | null;
    const nickname = joinNicknameEl?.value.trim() ?? '';
    const roomIdInput = joinRoomIdEl?.value.trim() ?? '';
    const urlRoomCode = getRoomCodeFromURL();
    const joinBtn = document.getElementById('btn-mp-action') as HTMLButtonElement;

    const nicknameValidation = validateNickname(nickname);
    if (!nicknameValidation.valid) {
        setFieldError(nicknameValidation.error ?? '', 'join-nickname-error');
        return;
    }

    // Use user input if provided, otherwise fall back to URL room code
    const roomId = roomIdInput || urlRoomCode;

    const roomValidation = validateRoomCode(roomId ?? '');
    if (!roomValidation.valid) {
        setFieldError(roomValidation.error ?? '', 'join-error');
        return;
    }

    cancelJoinOperation();
    joinAbortController = new AbortController();
    const signal = joinAbortController.signal;

    if (joinBtn) joinBtn.disabled = true;

    try {
        setMpStatus(t('multiplayer.connecting'), 'connecting');

        if (!EigennamenClient.isConnected()) {
            await EigennamenClient.connect();
        }

        if (signal.aborted) return;

        // Set up multiplayer event listeners BEFORE emitting join to prevent
        // race condition where game:started arrives before listeners are ready
        setupMultiplayerListeners();

        setMpStatus(t('multiplayer.joiningGame'), 'connecting');
        // Use toLocaleLowerCase('en-US') to match the server-side normalization
        // (toEnglishLowerCase).  Plain .toLowerCase() can differ for non-ASCII
        // characters depending on the browser locale, causing key mismatches.
        // roomId is guaranteed non-null here: validateRoomCode above rejects falsy values
        const normalizedRoomId = (roomId ?? '').toLocaleLowerCase('en-US');
        const result: JoinCreateResult = await EigennamenClient.joinRoom(normalizedRoomId, nickname);

        if (signal.aborted) return;

        // currentRoomId is now assigned inside onMultiplayerJoined (after the
        // room-change comparison) — pass the fallback so it can resolve it (H4).
        onMultiplayerJoined(result, false, normalizedRoomId);
    } catch (error: unknown) {
        const err = error as { name?: string; code?: string; message?: string };
        if (err.name === 'AbortError' || signal.aborted) return;

        logger.error(`Join failed for room "${roomId}":`, error);
        if (err.code === 'ROOM_NOT_FOUND') {
            // Switch to create mode so user can create the room with one click
            setMpMode('create');
            const createRoomInput = document.getElementById('create-room-id') as HTMLInputElement | null;
            if (createRoomInput) createRoomInput.value = roomId || '';
            // Copy nickname to create form so user doesn't re-enter it
            const createNicknameInput = document.getElementById('create-nickname') as HTMLInputElement | null;
            if (createNicknameInput) createNicknameInput.value = nickname;
            setMpStatus(t('multiplayer.roomNotFoundCreate', { roomId: roomId || '' }), 'error');
            // Don't clear room code from URL — user may create the room with the same code
        } else if (err.code === 'ROOM_FULL') {
            setMpStatus(t('errors.roomFull'), 'error');
        } else if (err.code === 'INVALID_INPUT') {
            setMpStatus(err.message || t('multiplayer.invalidInputDetail'), 'error');
        } else if (err.message?.includes('connect')) {
            setMpStatus(t('multiplayer.connectionFailedDetail'), 'error');
        } else {
            setMpStatus(err.message || t('multiplayer.joinFailed'), 'error');
        }
    } finally {
        if (joinBtn) joinBtn.disabled = false;
        joinAbortController = null;
    }
}

async function handleCreateGame(): Promise<void> {
    clearFormErrors();

    const createNicknameEl = document.getElementById('create-nickname') as HTMLInputElement | null;
    const createRoomIdEl = document.getElementById('create-room-id') as HTMLInputElement | null;
    const nickname = createNicknameEl?.value.trim() ?? '';
    const roomId = createRoomIdEl?.value.trim() ?? '';
    const createBtn = document.getElementById('btn-mp-action') as HTMLButtonElement;

    const nicknameValidation = validateNickname(nickname);
    if (!nicknameValidation.valid) {
        setFieldError(nicknameValidation.error ?? '', 'create-nickname-error');
        return;
    }

    const roomValidation = validateRoomCode(roomId);
    if (!roomValidation.valid) {
        setFieldError(roomValidation.error ?? '', 'create-error');
        return;
    }

    cancelCreateOperation();
    createAbortController = new AbortController();
    const signal = createAbortController.signal;

    if (createBtn) createBtn.disabled = true;

    try {
        setMpStatus(t('multiplayer.creatingGame'), 'connecting');

        if (!EigennamenClient.isConnected()) {
            await EigennamenClient.connect();
        }

        if (signal.aborted) return;

        // Set up multiplayer event listeners BEFORE emitting create to prevent
        // race condition where game:started arrives before listeners are ready
        setupMultiplayerListeners();

        // Use toLocaleLowerCase('en-US') to match the server-side normalization
        const normalizedRoomId = roomId.toLocaleLowerCase('en-US');
        const result: JoinCreateResult = await EigennamenClient.createRoom({
            roomId: normalizedRoomId,
            nickname: nickname,
        });

        if (signal.aborted) return;

        // currentRoomId is now assigned inside onMultiplayerJoined (after the
        // room-change comparison) — pass the fallback so it can resolve it (H4).
        onMultiplayerJoined(result, true, normalizedRoomId);
    } catch (error: unknown) {
        const err = error as { name?: string; code?: string; message?: string };
        if (err.name === 'AbortError' || signal.aborted) return;

        logger.error('Create failed:', error);
        if (err.code === 'ROOM_ALREADY_EXISTS') {
            setMpStatus(t('multiplayer.roomAlreadyExists'), 'error');
        } else if (err.message?.includes('connect')) {
            setMpStatus(t('multiplayer.connectionFailedDetail'), 'error');
        } else {
            setMpStatus(err.message || t('multiplayer.createFailed'), 'error');
        }
    } finally {
        if (createBtn) createBtn.disabled = false;
        createAbortController = null;
    }
}

export function onMultiplayerJoined(
    result: JoinCreateResult,
    isHostParam: boolean = false,
    fallbackRoomCode: string = ''
): void {
    // Detect room change and reset stale state. This owns the state.currentRoomId
    // assignment: callers used to set it *before* calling in, which made the
    // comparison below always compare the new code against itself (never true),
    // so a room switch left room A's index-addressed advisor-suggestion badges
    // rendered onto room B's board (H4). Comparing against the OLD value first,
    // then assigning, makes the reset actually fire.
    const newRoomCode = result.room?.code || fallbackRoomCode || null;
    if (state.currentRoomId && newRoomCode && state.currentRoomId !== newRoomCode) {
        resetMultiplayerState();
    }
    if (newRoomCode) {
        state.currentRoomId = newRoomCode;
    }

    state.isMultiplayerMode = true;
    safeSetItem('eigennamen-nickname', EigennamenClient.player?.nickname || '');

    // Start periodic sweep of stale reveal-pending entries
    startRevealSweep();

    // Listeners are now set up before join/create (in handleJoinGame/handleCreateGame)
    // to prevent race conditions. This guard handles the auto-rejoin path where
    // onMultiplayerJoined is called without going through handleJoinGame/handleCreateGame.
    setupMultiplayerListeners();

    // Store players list
    state.multiplayerPlayers = result.players || (result.player ? [result.player] : []);

    // Sync current player's team and role from server
    const currentPlayer: ServerPlayerData | undefined =
        result.you || result.player || EigennamenClient.player || undefined;
    if (currentPlayer) {
        syncLocalPlayerState(currentPlayer);
    }

    // Update global isHost from parameter or player data
    state.isHost = isHostParam || EigennamenClient.player?.isHost || false;

    // Sync team names from room settings (so non-host players see custom names)
    const roomSettings = result.room?.settings as { teamNames?: { red?: string; blue?: string } } | undefined;
    if (roomSettings?.teamNames) {
        if (roomSettings.teamNames.red) state.teamNames.red = roomSettings.teamNames.red;
        if (roomSettings.teamNames.blue) state.teamNames.blue = roomSettings.teamNames.blue;
    }

    // Sync game state from server if available, otherwise clear stale local state
    // (e.g., leftover board from standalone mode) to prevent card clicks when no
    // server-side game exists — which would trigger GAME_NOT_STARTED errors.
    if (result.game) {
        syncGameStateFromServer(result.game);
    } else {
        resetGameState();
        state.boardInitialized = false;
        renderBoard();
        updateScoreboard();
        updateTurnIndicator();

        // Auto-start a game when the host creates a room so the board is
        // immediately playable. Players who join later receive the game
        // state via the room:joined response.
        if (isHostParam && isClientConnected()) {
            EigennamenClient.startGame(buildStartGameOptions());
        }
    }

    // Update URL with room code for shareable links
    if (result.room?.code) {
        updateURLWithRoomCode(result.room.code);
    }

    // Update UI
    setMpStatus(t('multiplayer.connected'), 'success');
    updateMpIndicator(result.room || null, state.multiplayerPlayers);
    updateRoomSettingsNavVisibility();
    updateControls();
    updateRoleBanner();
    updateForfeitButton();

    // Close modal after brief delay and show appropriate message
    setTimeout(() => {
        closeMultiplayer();
        if (state.isHost && state.currentRoomId) {
            showToast(t('multiplayer.gameCreatedShare', { roomId: state.currentRoomId }), 'success', 8000);
        } else {
            showToast(t('multiplayer.connectedToGame'), 'success');
        }
    }, UI.MP_JOIN_CLOSE_DELAY_MS);
}

// Guard: prevent duplicate registration of multiplayer modal listeners
let mpModalInitialized = false;

export function initMultiplayerModal(): void {
    if (mpModalInitialized) return;
    mpModalInitialized = true;

    // Mode toggle buttons
    document.querySelectorAll('.mode-btn').forEach((btn) => {
        const el = btn as HTMLElement;
        el.addEventListener('click', () => setMpMode(el.dataset.mode || 'join'));
    });

    // Action button
    const actionBtn = document.getElementById('btn-mp-action');
    if (actionBtn) actionBtn.addEventListener('click', handleMpAction);

    // Enter key submits
    ['join-nickname', 'join-room-id', 'create-nickname', 'create-room-id'].forEach((id) => {
        const input = document.getElementById(id);
        if (input) {
            input.addEventListener('keypress', (e: KeyboardEvent) => {
                if (e.key === 'Enter') handleMpAction();
            });
        }
    });

    // Copy Room ID button
    const copyBtn = document.getElementById('btn-copy-room-id');
    if (copyBtn) {
        copyBtn.addEventListener('click', copyRoomId);
    }

    // Check for room code in URL after modal is initialized
    setTimeout(checkURLForRoomJoin, 100);
}

export function checkURLForRoomJoin(): void {
    // A shared replay link is `?replay=<gameId>&room=<roomCode>` — it reuses the
    // same `room` param the join flow reads. When `replay` is present the replay
    // loader (checkURLForReplayLoad) owns this URL; popping the join modal on top
    // would render a fresh local game underneath the replay. Let the replay win. (A9)
    if (new URLSearchParams(window.location.search).has('replay')) {
        return;
    }

    const roomCode = getRoomCodeFromURL();
    const roomValidation = validateRoomCode(roomCode ?? '');
    if (roomCode && roomValidation.valid) {
        // Pre-fill nickname from storage
        const storedNickname = safeGetItem('eigennamen-nickname', '') ?? '';
        const joinNicknameInput = document.getElementById('join-nickname') as HTMLInputElement | null;
        if (joinNicknameInput) joinNicknameInput.value = storedNickname;

        // Pre-fill room ID from URL
        const joinRoomInput = document.getElementById('join-room-id') as HTMLInputElement | null;
        if (joinRoomInput) joinRoomInput.value = roomCode;

        // Show multiplayer modal in join mode
        setMpMode('join');
        openModal('multiplayer-modal');

        setMpStatus(`Room ID: ${roomCode} - Enter your nickname to join`, 'info');
    }
}
