import { state, BOARD_SIZE } from './state.js';
import { showSpymasterView, isMatchMode } from './store/selectors.js';
import { getCardFontClass, fitCardText } from './utils.js';
import { t } from './i18n.js';
import { logger } from './logger.js';
// Use the single shared screen-reader announcer. board.ts previously had its own
// copy that wrote to the same #sr-announcements region with an independent clear
// timer; two uncoordinated writers could double-announce or wipe each other's
// message. One implementation, one timer.
import { announceToScreenReader } from './ui.js';

// Callback for card clicks - set via setCardClickHandler
let cardClickHandler: ((index: number) => void) | null = null;

/**
 * Build a descriptive ARIA label for a card (WCAG 2.1 AA).
 * @param word - Card word
 * @param isRevealed - Whether card is revealed
 * @param type - Card type (red, blue, neutral, assassin)
 * @param row - Grid row (1-indexed)
 * @param col - Grid column (1-indexed)
 * @returns Descriptive ARIA label
 */
function buildCardAriaLabel(word: string, isRevealed: boolean, type: string, row: number, col: number): string {
    const position = t('board.gridPosition', { row, col });
    if (isRevealed) {
        const typeLabel = type === 'assassin' ? t('board.assassinCard') : t('board.teamCard', { type });
        return t('board.revealedCardLabel', { word, typeLabel, position });
    }
    return t('board.unrevealedCardLabel', { word, position });
}

// Re-fit card text on resize (debounced).
// Stored as a named function so it can be removed when leaving a room.
let resizeTimer: ReturnType<typeof setTimeout> | null = null;
function handleResize(): void {
    if (resizeTimer) clearTimeout(resizeTimer);
    resizeTimer = setTimeout(() => {
        const board = document.getElementById('board');
        if (board && board.children.length > 0) {
            // Reset inline font sizes so CSS classes take effect at new size
            for (const card of board.querySelectorAll('.card:not(.multi-word)')) {
                (card as HTMLElement).style.fontSize = '';
            }
            fitCardText(board);
        }
    }, 150);
}
let resizeListenerAttached = false;

/**
 * Attach the window resize listener (idempotent).
 * Call once when the board is first rendered.
 */
export function attachResizeListener(): void {
    if (!resizeListenerAttached) {
        window.addEventListener('resize', handleResize);
        resizeListenerAttached = true;
    }
}

/**
 * Remove the window resize listener and cancel any pending debounce.
 * Call when leaving a room to prevent accumulating listeners.
 */
export function detachResizeListener(): void {
    if (resizeListenerAttached) {
        window.removeEventListener('resize', handleResize);
        resizeListenerAttached = false;
    }
    if (resizeTimer) {
        clearTimeout(resizeTimer);
        resizeTimer = null;
    }
}

export function setCardClickHandler(fn: (index: number) => void): void {
    cardClickHandler = fn;
}

export function canClickCards(): boolean {
    if (state.gameState.gameOver) return false;

    // Standalone mode: everyone can click (no team/role restrictions)
    if (!state.isMultiplayerMode) {
        return true;
    }

    // Multiplayer: clicker for the current team can always click
    if (state.clickerTeam && state.clickerTeam === state.gameState.currentTurn) {
        return true;
    }

    // In multiplayer: a plain team member can click if the clicker is
    // disconnected — but NOT the spymaster, an observer, or an advisor. The
    // server forbids all three from revealing (gameHandlers.ts), so offering
    // them the fallback only produces bounced actions and cleared reveal flags.
    if (
        state.playerTeam === state.gameState.currentTurn &&
        !state.spymasterTeam &&
        !state.isObserver &&
        !state.isAdvisor
    ) {
        const teamClicker = state.multiplayerPlayers.find(
            (p) => p.team === state.gameState.currentTurn && p.role === 'clicker'
        );
        // Allow if no clicker assigned or clicker is disconnected
        if (!teamClicker || !teamClicker.connected) {
            return true;
        }
    }

    return false;
}

// Initialize board event delegation (called once)
export function initBoardEventDelegation(): void {
    const board = state.cachedElements.board || document.getElementById('board');
    if (!board || board.hasAttribute('data-delegated')) return;

    // Single click handler using event delegation
    board.addEventListener('click', (e) => {
        const card = (e.target as Element).closest('.card');
        if (!card || card.classList.contains('revealed')) return;
        // Use data-index attribute for O(1) lookup instead of indexOf
        const index = parseInt((card as HTMLElement).dataset.index!, 10);
        if (!isNaN(index) && index >= 0 && cardClickHandler) cardClickHandler(index);
    });

    // Single keydown handler using event delegation
    board.addEventListener('keydown', (e) => {
        const card = (e.target as Element).closest('.card');
        if (!card) return;
        // Use data-index attribute for O(1) lookup instead of indexOf
        const index = parseInt((card as HTMLElement).dataset.index!, 10);
        if (isNaN(index) || index < 0) return;

        if ((e as KeyboardEvent).key === 'Enter' || (e as KeyboardEvent).key === ' ') {
            e.preventDefault();
            if (!card.classList.contains('revealed')) {
                if (cardClickHandler) cardClickHandler(index);
            }
        } else if (
            ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', 'Home', 'End'].includes((e as KeyboardEvent).key)
        ) {
            e.preventDefault();
            navigateCards(index, (e as KeyboardEvent).key);
        }
    });

    board.setAttribute('data-delegated', 'true');
}

/**
 * Get the CSS class for a card score badge value.
 */
function getScoreBadgeClass(score: number): string {
    if (score === 3) return 'card-score-gold';
    if (score === 2) return 'card-score-silver';
    if (score === 1) return 'card-score-standard';
    if (score === 0) return 'card-score-blank';
    return 'card-score-trap'; // negative
}

/**
 * Create or update a score badge element on a card.
 * Shows card point values in match mode.
 * Visible to spymasters (all cards) and everyone (revealed cards).
 */
function updateCardScoreBadge(card: HTMLElement, index: number): void {
    const existingBadge = card.querySelector('.card-score-badge');
    if (!isMatchMode()) {
        if (existingBadge) existingBadge.remove();
        return;
    }

    const cardScores = state.gameState.cardScores;
    if (!cardScores || cardScores.length === 0) {
        if (existingBadge) existingBadge.remove();
        return;
    }

    const score = cardScores[index];
    const isRevealed = state.gameState.revealed[index];
    const isSpyView = showSpymasterView();

    // Score is visible if card is revealed or player is spymaster/game over
    if (score === null || score === undefined || (!isRevealed && !isSpyView)) {
        if (existingBadge) existingBadge.remove();
        return;
    }

    const badgeClass = getScoreBadgeClass(score);
    const displayText = score > 0 ? `+${score}` : String(score);

    if (existingBadge) {
        existingBadge.className = `card-score-badge ${badgeClass}`;
        existingBadge.textContent = displayText;
    } else {
        const badge = document.createElement('span');
        badge.className = `card-score-badge ${badgeClass}`;
        badge.textContent = displayText;
        card.appendChild(badge);
    }
}

// Guard against concurrent or interleaved renders from overlapping socket events.
// Covers both renderBoard (full) and updateBoardIncremental (partial) — if either
// is in progress, the other is skipped to prevent stale DOM references.
let renderingInProgress = false;
// Set when a renderBoard call is skipped due to renderingInProgress.
// The next renderBoard call will force a full re-render instead of incremental.
let pendingFullRender = false;

export function renderBoard(): void {
    const board = state.cachedElements.board || document.getElementById('board');
    if (!board) return;

    try {
        // Update board class
        let className = 'board';
        if (showSpymasterView()) className += ' spymaster-mode';
        if (!canClickCards()) className += ' no-click';
        board.className = className;

        // Check if we can do an incremental update (skip if a full render was deferred)
        if (!pendingFullRender && state.boardInitialized && board.children.length === BOARD_SIZE) {
            updateBoardIncremental();
            return;
        }

        // Prevent concurrent full re-renders from overlapping socket messages.
        // If a render is already in progress, mark a pending rerender so the
        // next call forces a full rebuild instead of using the incremental path.
        if (renderingInProgress) {
            pendingFullRender = true;
            return;
        }
        renderingInProgress = true;
        pendingFullRender = false;

        // Full re-render (only for new games)
        board.replaceChildren();

        // Board-level accessibility: grid role and description
        board.setAttribute('role', 'grid');
        board.setAttribute('aria-label', t('board.boardAriaLabel'));

        state.gameState.words.forEach((word, index) => {
            const card = document.createElement('div');
            const fontClass = getCardFontClass(word);
            card.className = `card ${fontClass}`;
            if (word.includes(' ')) {
                card.classList.add('multi-word');
            }
            card.textContent = word;
            card.dataset.word = word;
            card.setAttribute('data-index', String(index));
            card.setAttribute('data-testid', 'board-card');

            // Accessibility: make cards focusable and add ARIA attributes
            const isRevealed = state.gameState.revealed[index];
            const row = Math.floor(index / 5) + 1;
            const col = (index % 5) + 1;
            card.setAttribute('role', 'gridcell');
            card.setAttribute('tabindex', isRevealed ? '-1' : '0');
            card.setAttribute(
                'aria-label',
                buildCardAriaLabel(word, isRevealed ?? false, state.gameState.types[index] ?? '', row, col)
            );
            if (isRevealed) {
                card.setAttribute('aria-disabled', 'true');
            }

            // Add spymaster hints (show all card types when game is over)
            if (showSpymasterView()) {
                card.classList.add(`spy-${state.gameState.types[index] ?? 'neutral'}`);
            }

            // Show revealed cards
            if (isRevealed) {
                const revealedType = state.gameState.types[index];
                if (!revealedType) {
                    logger.warn(`renderBoard: revealed card ${index} has null type, falling back to neutral`);
                }
                card.classList.add('revealed', revealedType || 'neutral');
                // Add clicked-by class to mark the score badge with the team that clicked
                const clickedBy = state.gameState.revealedBy?.[index];
                if (clickedBy) {
                    card.classList.add(`clicked-by-${clickedBy}`);
                }
            }

            // Match mode: add score badge
            updateCardScoreBadge(card, index);

            board.appendChild(card);
        });

        // Shrink font on any single-word cards that overflow their container
        fitCardText(board);

        // Re-apply any active advisor suggestions after a full rebuild.
        renderBotSuggestions();

        state.boardInitialized = true;
        renderingInProgress = false;
        initBoardEventDelegation();
        attachResizeListener();
        // If another renderBoard() was requested while this one was running it
        // was skipped (renderingInProgress) with pendingFullRender left set.
        // Honor it now — otherwise that request is silently dropped, which can
        // leave the board empty (e.g. a reactive render fired during newGame()
        // that the explicit game-start render overtook). pendingFullRender stays
        // set so the re-entrant call takes the full-rebuild path.
        if (pendingFullRender) {
            renderBoard();
        }
    } catch (err) {
        renderingInProgress = false;
        logger.error('renderBoard failed:', err);
        // Show a minimal fallback so the board area isn't blank
        board.replaceChildren();
        const errorDiv = document.createElement('div');
        errorDiv.className = 'board-error';
        errorDiv.textContent = t('board.renderError');
        board.appendChild(errorDiv);
    }
}

/**
 * Overlay advisor-bot guess suggestions on the board: a highlight ring + a
 * confidence badge (reason as tooltip) on each suggested card. Advisory only —
 * the human clicker still clicks to reveal.
 */
export function renderBotSuggestions(): void {
    const board = state.cachedElements.board || document.getElementById('board');
    if (!board) return;
    board.querySelectorAll('.card.suggested').forEach((c) => {
        c.classList.remove('suggested');
        c.removeAttribute('data-confidence');
        c.querySelector('.suggestion-badge')?.remove();
    });
    for (const s of state.botSuggestions) {
        // Shape-guard server data before it reaches a selector template or
        // the DOM: only a non-negative integer index is ever interpolated,
        // and only real numbers render as a confidence.
        if (!Number.isInteger(s.index) || s.index < 0 || typeof s.confidence !== 'number') continue;
        const card = board.querySelector(`.card[data-index="${s.index}"]`);
        if (!card || card.classList.contains('revealed')) continue;
        const pct = Math.round(Math.max(0, Math.min(1, s.confidence)) * 100);
        card.classList.add('suggested');
        card.setAttribute('data-confidence', String(pct));
        const badge = document.createElement('span');
        badge.className = 'suggestion-badge';
        // An advisor caution (late stretch, frame doubt, unresolved reference)
        // is flagged on the badge and detailed in the tooltip. textContent
        // only — advisory strings never touch innerHTML — and non-string
        // fields degrade to absent rather than rendering "[object Object]".
        const reason = typeof s.reason === 'string' ? s.reason : '';
        const warning = typeof s.warning === 'string' ? s.warning : undefined;
        badge.textContent = warning ? `⚠ ${pct}%` : `${pct}%`;
        const detail = warning ? `${reason} — ${warning}` : reason;
        badge.title = state.botSuggestionAdvisor ? `${state.botSuggestionAdvisor}: ${detail}` : detail;
        card.appendChild(badge);
    }
}

/** Clear all advisor suggestions and their board decorations. */
export function clearBotSuggestions(): void {
    state.botSuggestions = [];
    state.botSuggestionAdvisor = null;
    renderBotSuggestions();
}

// Incremental update - only update changed cards (much faster)
export function updateBoardIncremental(): void {
    const board = state.cachedElements.board || document.getElementById('board');
    if (!board) return;
    // Skip if a full render is in progress — our DOM references may be stale
    if (renderingInProgress) return;

    try {
        // Update board class
        let className = 'board';
        if (showSpymasterView()) className += ' spymaster-mode';
        if (!canClickCards()) className += ' no-click';
        board.className = className;

        let needsFit = false;
        const cards = board.children;
        const wordCount = state.gameState.words.length;
        for (let index = 0; index < cards.length; index++) {
            const card = cards[index] as HTMLElement;
            // Guard against array length mismatch between DOM and state
            if (index >= wordCount) break;
            const isRevealed = state.gameState.revealed[index];
            const type = state.gameState.types[index] ?? 'neutral';
            const word = state.gameState.words[index] ?? '';

            // Update card text if it changed (safety measure for sync issues)
            // Compare via data-word to avoid false mismatches from badge child text
            if (card.dataset.word !== word) {
                card.textContent = word;
                card.dataset.word = word;
                // Update font class based on word length
                card.classList.remove('font-lg', 'font-md', 'font-sm', 'font-xs', 'font-min');
                card.style.fontSize = ''; // clear any fitCardText override
                const fontClass = getCardFontClass(word);
                if (fontClass) card.classList.add(fontClass);
                // Update multi-word class
                if (word.includes(' ')) {
                    card.classList.add('multi-word');
                } else {
                    card.classList.remove('multi-word');
                }
                needsFit = true;
            }

            // Update ARIA
            const row = Math.floor(index / 5) + 1;
            const col = (index % 5) + 1;
            card.setAttribute('tabindex', isRevealed ? '-1' : '0');
            card.setAttribute('aria-label', buildCardAriaLabel(word, isRevealed ?? false, type, row, col));
            if (isRevealed) {
                card.setAttribute('aria-disabled', 'true');
            } else {
                card.removeAttribute('aria-disabled');
            }

            // Handle spymaster mode (show all card types when game is over)
            // Always remove old spy- classes first to prevent stale classes
            // from winning via CSS cascade (e.g. spy-neutral from null types
            // before spymasterView event arrives with real types)
            card.classList.remove('spy-red', 'spy-blue', 'spy-neutral', 'spy-assassin');
            if (showSpymasterView()) {
                card.classList.add(`spy-${type}`);
            }

            // Handle reveal state
            if (isRevealed) {
                if (!card.classList.contains('revealed')) {
                    // First time marking as revealed — add class + animation
                    card.classList.add('revealed', type);

                    // Add clicked-by class to mark the score badge with the team that clicked
                    const clickedBy = state.gameState.revealedBy?.[index];
                    if (clickedBy) {
                        card.classList.add(`clicked-by-${clickedBy}`);
                    }

                    if (index === state.lastRevealedIndex) {
                        if (state.lastRevealedWasCorrect) {
                            card.classList.add('success-reveal');
                        } else {
                            card.classList.add('just-revealed');
                        }
                    }
                } else if (!card.classList.contains(type)) {
                    // Already revealed but type class is wrong/missing (e.g. was 'neutral'
                    // fallback before server sent the real type). Fix it.
                    card.classList.remove('red', 'blue', 'neutral', 'assassin');
                    card.classList.add(type);
                }
                // Ensure clicked-by class is present on already-revealed cards
                const clickedByInc = state.gameState.revealedBy?.[index];
                if (clickedByInc && !card.classList.contains(`clicked-by-${clickedByInc}`)) {
                    card.classList.remove('clicked-by-red', 'clicked-by-blue');
                    card.classList.add(`clicked-by-${clickedByInc}`);
                }
            } else if (card.classList.contains('revealed')) {
                // Card was revealed in a previous game but is unrevealed in the new game.
                // Remove stale revealed/type classes that could persist from orphaned rAFs
                // or incremental updates that ran before the full re-render.
                card.classList.remove(
                    'revealed',
                    'red',
                    'blue',
                    'neutral',
                    'assassin',
                    'just-revealed',
                    'success-reveal',
                    'clicked-by-red',
                    'clicked-by-blue'
                );
            }

            // Match mode: update score badge
            updateCardScoreBadge(card, index);
        }

        if (needsFit) {
            fitCardText(board);
        }
    } catch (err) {
        logger.error('updateBoardIncremental failed:', err);
    }
}

// Update single card (for card reveal animation)
export function updateSingleCard(index: number): void {
    const board = state.cachedElements.board || document.getElementById('board');
    if (!board || !board.children[index]) return;
    // Guard against array length mismatch
    if (index >= state.gameState.types.length || index >= state.gameState.words.length) return;

    const card = board.children[index] as HTMLElement;
    const type = state.gameState.types[index] ?? 'neutral';

    // Remove any stale type class before adding the correct one
    card.classList.remove('red', 'blue', 'neutral', 'assassin', 'clicked-by-red', 'clicked-by-blue');
    card.classList.add('revealed', type);
    card.setAttribute('tabindex', '-1');
    const word = state.gameState.words[index] ?? '';
    const row = Math.floor(index / 5) + 1;
    const col = (index % 5) + 1;
    card.setAttribute('aria-label', buildCardAriaLabel(word, true, type, row, col));

    // Add clicked-by class to mark the score badge with the team that clicked
    const clickedBy = state.gameState.revealedBy?.[index];
    if (clickedBy) {
        card.classList.add(`clicked-by-${clickedBy}`);
    }

    // Announce reveal to screen readers (localized)
    const typeNames: Record<string, string> = {
        red: state.teamNames.red,
        blue: state.teamNames.blue,
        neutral: t('rules.neutralCard'),
        assassin: t('board.assassinCard'),
    };
    const typeName = typeNames[type] || type;
    announceToScreenReader(t('game.wordRevealedAs', { word, type: typeName }));

    // Add animation class
    if (state.lastRevealedWasCorrect) {
        card.classList.add('success-reveal');
    } else {
        card.classList.add('just-revealed');
    }

    // Match mode: show score badge on revealed card
    updateCardScoreBadge(card, index);
}

// Arrow key navigation for cards (5x5 grid)
export function navigateCards(currentIndex: number, key: string): void {
    const COLS = 5;
    const ROWS = 5;
    const TOTAL = COLS * ROWS;
    const row = Math.floor(currentIndex / COLS);
    const col = currentIndex % COLS;

    let newIndex = currentIndex;

    switch (key) {
        case 'ArrowUp':
            // Wrap to bottom of same column if at top
            newIndex = row > 0 ? currentIndex - COLS : (ROWS - 1) * COLS + col;
            break;
        case 'ArrowDown':
            // Wrap to top of same column if at bottom
            newIndex = row < ROWS - 1 ? currentIndex + COLS : col;
            break;
        case 'ArrowLeft':
            // Wrap to end of previous row if at start
            newIndex = currentIndex > 0 ? currentIndex - 1 : TOTAL - 1;
            break;
        case 'ArrowRight':
            // Wrap to start of next row if at end
            newIndex = currentIndex < TOTAL - 1 ? currentIndex + 1 : 0;
            break;
        case 'Home':
            // Go to first card in current row
            newIndex = row * COLS;
            break;
        case 'End':
            // Go to last card in current row
            newIndex = row * COLS + (COLS - 1);
            break;
    }

    if (newIndex !== currentIndex && newIndex >= 0 && newIndex < TOTAL) {
        const board = state.cachedElements.board || document.getElementById('board');
        if (board && board.children[newIndex]) {
            (board.children[newIndex] as HTMLElement).focus();
        }
    }
}
