import { state } from '../state.js';
import { showToast } from '../ui.js';
import { t } from '../i18n.js';
import { updateRoleBanner, updateControls, revertAndClearRoleChange } from '../roles.js';
import { renderBoard } from '../board.js';
import { updateScoreboard, updateTurnIndicator } from '../game.js';
import { logger } from '../logger.js';
import {
    updateMpIndicator,
    updateForfeitButton,
    updateRoomSettingsNavVisibility,
    showReconnectionOverlay,
    hideReconnectionOverlay,
    syncGameModeUI,
    syncTurnTimerUI,
    syncAllowSpectatorsUI,
} from '../multiplayerUI.js';
import {
    syncGameStateFromServer,
    syncLocalPlayerState,
    leaveMultiplayerMode,
    detectOfflineChanges,
    domListenerCleanup,
    updateURLWithRoomCode,
} from '../multiplayerSync.js';
import { batch } from '../store/batch.js';
import type {
    ServerPlayerData,
    HostChangedData,
    RoomWarningData,
    ReconnectionData,
    SettingsUpdatedData,
    StatsUpdatedData,
    KickedData,
    PlayerKickedData,
} from '../multiplayerTypes.js';
import { updateSpectatorCount, updateRoomStats } from '../multiplayerUI.js';
import { getClient } from '../clientAccessor.js';

/**
 * Sync team names from room settings into local state.
 * Used during join, resync, and reconnection to ensure all players
 * see the host's custom team names.
 */
function syncTeamNamesFromRoom(room: { settings?: Record<string, unknown> } | null | undefined): void {
    const settings = room?.settings as { teamNames?: { red?: string; blue?: string } } | undefined;
    if (settings?.teamNames) {
        if (settings.teamNames.red) state.teamNames.red = settings.teamNames.red;
        if (settings.teamNames.blue) state.teamNames.blue = settings.teamNames.blue;
    }
}

export function registerRoomHandlers(): void {
    // Handle host change (when previous host disconnects)
    EigennamenClient.on('hostChanged', (data: HostChangedData) => {
        if (state.resyncInProgress) return;
        // Update global isHost based on whether we became the new host
        const wasHost = state.isHost;
        state.isHost = data.newHostSessionId === EigennamenClient.player?.sessionId;

        // Update host status in players list
        if (data.newHostSessionId) {
            state.multiplayerPlayers = state.multiplayerPlayers.map((p: ServerPlayerData) => ({
                ...p,
                isHost: p.sessionId === data.newHostSessionId,
            }));
            updateMpIndicator({ code: EigennamenClient.getRoomCode() || '' }, state.multiplayerPlayers);
        }

        // Update UI elements that depend on host status
        updateRoomSettingsNavVisibility();
        updateRoleBanner();
        updateForfeitButton();

        if (state.isHost && !wasHost) {
            showToast(t('multiplayer.youAreHost'), 'info');
        } else if (data.newHostNickname) {
            showToast(t('multiplayer.newHost', { name: data.newHostNickname }), 'info');
        }
    });

    // Room warnings (non-fatal issues like stale stats)
    EigennamenClient.on('roomWarning', (data: RoomWarningData) => {
        if (data.code === 'STATS_STALE') {
            // Auto-request resync to get fresh data
            EigennamenClient.requestResync().catch(() => {
                // Resync failed, stats may remain stale - not critical
                logger.warn('Auto-resync after stale stats warning failed');
            });
        } else if (data.code === 'BOT_STALLED') {
            // A stuck bot seat had its turn force-ended server-side
            // (docs/HARDENING_PLAN.md P1-6) — this must actually reach the
            // player, not just the server log, or the turn flip looks unexplained.
            showToast(t('multiplayer.botStalled', { team: data.team ?? '' }), 'warning');
        } else if (data.code === 'BOT_SEAT_RECLAIMED') {
            // A reconnecting human evicted a bot that was standing in on their
            // seat (docs/HARDENING_PLAN.md P1-7) — surface why the bot vanished.
            showToast(t('multiplayer.botSeatReclaimed', { team: data.team ?? '' }), 'info');
        } else if (data.code === 'SERVER_SHUTDOWN') {
            // The server is restarting (e.g. a deploy). In memory mode the game
            // cannot be resumed, so tell the player why it's about to vanish.
            showToast(t('multiplayer.serverShutdown'), 'warning');
        } else if (data.message) {
            // Unknown warning code: surface the server-provided message rather
            // than silently dropping it, so future codes degrade gracefully.
            showToast(data.message, 'warning');
        }
    });

    // Room resync (state recovery) — batch state mutations (M7 from audit)
    EigennamenClient.on('roomResynced', (data: ReconnectionData) => {
        // Guard: prevent individual update events from interleaving with
        // a full resync, which replaces all state atomically.
        state.resyncInProgress = true;
        try {
            batch(() => {
                // Sync current player's state from server response
                const currentPlayer = data.you || EigennamenClient.player;
                if (currentPlayer) {
                    syncLocalPlayerState(currentPlayer as ServerPlayerData);
                }
                if (data.players) {
                    state.multiplayerPlayers = data.players;
                }
            });

            // Sync team names from room settings before game state sync
            // so that updateScoreboard() in syncGameStateFromServer shows correct names
            syncTeamNamesFromRoom(data.room);

            if (data.game) {
                syncGameStateFromServer(data.game);
            }
            if (data.players) {
                updateMpIndicator(data.room || null, state.multiplayerPlayers);
            }

            // Clear stale reveal tracking — any cardRevealed events were skipped
            // during resync, so pending entries in revealingCards are now stale.
            // Without this, cards clicked just before a resync become permanently
            // unclickable until the per-card timeout fires.
            state.revealTimeouts.forEach((timeoutId) => clearTimeout(timeoutId));
            state.revealTimeouts.clear();
            state.revealingCards.clear();
            state.revealTimestamps.clear();
            state.isRevealingCard = false;
            document.querySelectorAll('.card.revealing').forEach((c) => c.classList.remove('revealing'));

            // Update all UI elements
            updateControls();
            updateRoleBanner();
        } finally {
            state.resyncInProgress = false;
        }
    });

    // Disconnect handling
    EigennamenClient.on('disconnected', () => {
        // Use revertAndClearRoleChange (not clearRoleChange) so that buttons
        // are reverted from 'loading' state back to their previous DOM state.
        revertAndClearRoleChange();
        showToast(t('multiplayer.disconnectedFromServer'), 'warning');
        // Show reconnection overlay if we were in a room
        if (state.isMultiplayerMode) {
            showReconnectionOverlay();
        }
    });

    // Show reconnection overlay when auto-rejoin is being attempted
    EigennamenClient.on('rejoining', () => {
        showReconnectionOverlay();
    });

    // Shared reconnection handler (used by both auto-rejoin and token-based reconnection)
    // Wraps state updates in batch() to prevent intermediate renders (M7 from audit)
    function handleReconnection(data: ReconnectionData): void {
        hideReconnectionOverlay();

        // Guard: full state replacement — defer individual update events
        state.resyncInProgress = true;
        try {
            const changes = detectOfflineChanges(data);

            batch(() => {
                const currentPlayer = data?.you || EigennamenClient.player;
                if (currentPlayer) {
                    syncLocalPlayerState(currentPlayer as ServerPlayerData);
                }
                if (data?.players) {
                    state.multiplayerPlayers = data.players;
                }
            });

            // Sync team names from room settings before game state sync
            syncTeamNamesFromRoom(data?.room);

            if (data?.game) {
                syncGameStateFromServer(data.game);
            }
            if (data?.players) {
                updateMpIndicator(data?.room || null, state.multiplayerPlayers);
            }

            // Clear stale reveal tracking — pending reveals from before
            // disconnect are no longer valid after reconnection.
            state.revealTimeouts.forEach((timeoutId) => clearTimeout(timeoutId));
            state.revealTimeouts.clear();
            state.revealingCards.clear();
            state.revealTimestamps.clear();
            state.isRevealingCard = false;
            document.querySelectorAll('.card.revealing').forEach((c) => c.classList.remove('revealing'));

            updateControls();
            updateRoleBanner();
            updateForfeitButton();

            // Heal the shareable URL back to ?room=CODE. A disconnect-era action
            // that slipped into the standalone engine (or a stale load) can leave
            // a standalone ?game=… URL; without this a later refresh would load a
            // standalone game instead of rejoining the room.
            const reconnectedRoomCode = data?.room?.code || state.currentRoomId;
            if (reconnectedRoomCode) {
                updateURLWithRoomCode(reconnectedRoomCode);
            }

            if (changes.length > 0) {
                showToast(t('multiplayer.reconnectedWithChanges', { changes: changes.join('. ') }), 'info', 6000);
            } else {
                showToast(t('multiplayer.reconnected'), 'success');
            }
        } finally {
            state.resyncInProgress = false;
        }
    }

    EigennamenClient.on('rejoined', handleReconnection);
    EigennamenClient.on('roomReconnected', handleReconnection);

    EigennamenClient.on('rejoinFailed', (data: ReconnectionData) => {
        // Hide reconnection overlay
        hideReconnectionOverlay();

        if (data.error?.code === 'ROOM_NOT_FOUND') {
            showToast(t('multiplayer.previousGameGone'), 'warning');
        } else {
            showToast(t('multiplayer.couldNotRejoin'), 'warning');
        }
        // Reset multiplayer state properly — wrapped in try/catch so that
        // if any part of cleanup throws, the UI is never left stuck in
        // multiplayer mode with a dead room code.
        try {
            leaveMultiplayerMode();
        } catch (e) {
            logger.error('leaveMultiplayerMode threw during rejoinFailed:', e);
            // Ensure critical state is always reset even if cleanup fails
            state.isMultiplayerMode = false;
            state.currentRoomId = null;
            state.multiplayerListenersSetup = false;
            state.multiplayerPlayers = [];
        }
    });

    // Handle being kicked from the room
    EigennamenClient.on('kicked', (data: KickedData) => {
        leaveMultiplayerMode();
        showToast(data.reason || t('multiplayer.kicked'), 'error', 5000);
    });

    // Handle another player being kicked
    EigennamenClient.on('playerKicked', (data: PlayerKickedData) => {
        if (state.resyncInProgress) return;
        // Update player list
        state.multiplayerPlayers = state.multiplayerPlayers.filter(
            (p: ServerPlayerData) => p.sessionId !== data.sessionId
        );
        updateMpIndicator({ code: EigennamenClient.getRoomCode() || '' }, state.multiplayerPlayers);
        // Refresh controls and board — kicked player may have held the active
        // clicker role, so remaining team members need UI updated for fallback.
        updateControls();
        renderBoard();
        showToast(t('multiplayer.playerKicked', { name: data.nickname || t('multiplayer.aPlayer') }), 'info');
    });

    // Handle room settings updates
    EigennamenClient.on('settingsUpdated', (data: SettingsUpdatedData) => {
        if (data.settings) {
            // Update room info display
            updateRoomSettingsNavVisibility();

            // Sync game mode radio buttons
            if (data.settings.gameMode) {
                syncGameModeUI(data.settings.gameMode);
            }

            // Sync team names
            const teamNames = data.settings.teamNames as { red?: string; blue?: string } | undefined;
            if (teamNames) {
                if (teamNames.red) state.teamNames.red = teamNames.red;
                if (teamNames.blue) state.teamNames.blue = teamNames.blue;
                updateScoreboard();
                updateTurnIndicator();
                updateRoleBanner();
            }

            // Sync turn timer UI
            syncTurnTimerUI(data.settings.turnTimer ?? null);

            // Sync allow-spectators toggle (F2)
            if ('allowSpectators' in data.settings) {
                syncAllowSpectatorsUI(data.settings.allowSpectators);
            }

            // Update multiplayer indicator
            updateMpIndicator({ code: EigennamenClient.getRoomCode() || '' }, state.multiplayerPlayers);

            showToast(t('multiplayer.settingsUpdated'), 'info');
        }
    });

    // Game mode radio button change handler — track for cleanup
    const gameModeRadios = document.querySelectorAll('input[name="gameMode"]');
    gameModeRadios.forEach((radio) => {
        const handler = (e: Event) => {
            if (!getClient()?.player?.isHost) return;
            const gameMode = (e.target as HTMLInputElement).value;
            EigennamenClient.updateSettings({ gameMode });
        };
        radio.addEventListener('change', handler);
        domListenerCleanup.push({ element: radio, event: 'change', handler });
    });

    // Turn timer toggle and slider handlers
    const timerToggle = document.getElementById('turn-timer-toggle') as HTMLInputElement;
    const timerSliderContainer = document.getElementById('turn-timer-slider');
    const timerRange = document.getElementById('turn-timer-range') as HTMLInputElement;
    const timerValue = document.getElementById('turn-timer-value');

    if (timerToggle) {
        const toggleHandler = () => {
            if (!getClient()?.player?.isHost) return;
            if (timerToggle.checked) {
                if (timerSliderContainer) timerSliderContainer.hidden = false;
                const seconds = parseInt(timerRange?.value || '120', 10);
                EigennamenClient.updateSettings({ turnTimer: seconds });
            } else {
                if (timerSliderContainer) timerSliderContainer.hidden = true;
                EigennamenClient.updateSettings({ turnTimer: null });
            }
        };
        timerToggle.addEventListener('change', toggleHandler);
        domListenerCleanup.push({ element: timerToggle, event: 'change', handler: toggleHandler });
    }

    if (timerRange) {
        const rangeHandler = () => {
            if (!getClient()?.player?.isHost) return;
            const seconds = parseInt(timerRange.value, 10);
            if (timerValue) timerValue.textContent = `${seconds}s`;
            EigennamenClient.updateSettings({ turnTimer: seconds });
        };
        timerRange.addEventListener('input', rangeHandler);
        domListenerCleanup.push({ element: timerRange, event: 'input', handler: rangeHandler });
    }

    // Allow-spectators toggle handler (F2) — host-only
    const spectatorsToggle = document.getElementById('allow-spectators-toggle') as HTMLInputElement | null;
    if (spectatorsToggle) {
        const spectatorsHandler = () => {
            if (!getClient()?.player?.isHost) return;
            EigennamenClient.updateSettings({ allowSpectators: spectatorsToggle.checked });
        };
        spectatorsToggle.addEventListener('change', spectatorsHandler);
        domListenerCleanup.push({ element: spectatorsToggle, event: 'change', handler: spectatorsHandler });
    }

    // Handle room stats updates (spectator count, team counts)
    EigennamenClient.on('statsUpdated', (data: StatsUpdatedData) => {
        if (data.stats) {
            updateSpectatorCount(data.stats.spectatorCount || 0);
            updateRoomStats(data.stats);
        }
    });
}
